import React from 'react';

const Bio = () => {
  return (
    <section className="bg-[#0F172A] py-20 text-white">
      <div className="container mx-auto px-6 flex flex-col md:flex-row items-center gap-12">
        {/* Lado de la Foto */}
        <div className="w-full md:w-1/3">
          <div className="aspect-[3/4] rounded-3xl overflow-hidden shadow-2xl ring-4 ring-slate-800">
            <img 
              src="/assets/maribel-perfil.jpg" 
              alt="Maribel Ferradas" 
              className="w-full h-full object-cover"
              onError={(e) => { e.target.src = "https://via.placeholder.com/400x500?text=Maribel"; }}
            />
          </div>
        </div>

        {/* Lado del Texto */}
        <div className="w-full md:w-2/3">
          <span className="text-blue-400 font-bold tracking-widest text-xs uppercase">Agente Inmobiliaria</span>
          <h2 className="text-3xl md:text-4xl font-bold mt-2 mb-6">Maribel Ferradas</h2>
          <p className="text-slate-300 text-lg leading-relaxed mb-6 italic">
            "Mi compromiso es transformar la búsqueda de tu hogar en una experiencia de paz y seguridad."
          </p>
          <div className="bg-slate-800/50 p-4 rounded-xl inline-block">
            <p className="text-xs text-slate-400">Registro Ministerio de Vivienda:</p>
            <p className="text-sm font-mono font-bold text-blue-300 uppercase">PN-XXXX-MVCS</p>
          </div>
        </div>
      </div>
    </section>
  );
};

export default Bio;
